import{_ as a,o as r,c as e,a7 as i}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"战斗系统","description":"","frontmatter":{},"headers":[],"relativePath":"modes/combat.md","filePath":"zh/modes/combat.md","lastUpdated":1775394001000}'),l={name:"modes/combat.md"};function o(s,t,d,n,h,c){return r(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="战斗系统" tabindex="-1">战斗系统 <a class="header-anchor" href="#战斗系统" aria-label="Permalink to &quot;战斗系统&quot;">​</a></h1><p>忘却前夜采用 <strong>回合制卡牌战斗</strong> 系统，在 2D 横版视角下进行。</p><h2 id="战斗基础" tabindex="-1">战斗基础 <a class="header-anchor" href="#战斗基础" aria-label="Permalink to &quot;战斗基础&quot;">​</a></h2><h3 id="回合流程" tabindex="-1">回合流程 <a class="header-anchor" href="#回合流程" aria-label="Permalink to &quot;回合流程&quot;">​</a></h3><ol><li><strong>抽牌阶段</strong> - 从卡组中抽取卡牌到手牌</li><li><strong>行动阶段</strong> - 消耗算力打出卡牌</li><li><strong>结束阶段</strong> - 触发回合结束效果，进入敌方回合</li></ol><h3 id="算力系统-arithmetica" tabindex="-1">算力系统（Arithmetica） <a class="header-anchor" href="#算力系统-arithmetica" aria-label="Permalink to &quot;算力系统（Arithmetica）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>数值</th></tr></thead><tbody><tr><td>每回合基础算力</td><td>5 点</td></tr><tr><td>卡牌消耗范围</td><td>1~5 算力不等</td></tr><tr><td>算力上限</td><td>可通过效果提升</td></tr></tbody></table><p>算力是打出卡牌的资源，合理管理算力是战斗胜利的关键。</p><h3 id="狂气系统-madness-points" tabindex="-1">狂气系统（Madness Points） <a class="header-anchor" href="#狂气系统-madness-points" aria-label="Permalink to &quot;狂气系统（Madness Points）&quot;">​</a></h3><ul><li>通过使用卡牌和受击等方式积累狂气</li><li>狂气积累至 <strong>100 点</strong> 时触发 <strong>狂气爆发（Madness Burst）</strong></li><li>狂气爆发不消耗算力，效果极其强力</li><li>合理控制狂气积累节奏是进阶技巧</li></ul><h3 id="银钥系统-silver-key" tabindex="-1">银钥系统（Silver Key） <a class="header-anchor" href="#银钥系统-silver-key" aria-label="Permalink to &quot;银钥系统（Silver Key）&quot;">​</a></h3><ul><li>使用卡牌会积累银钥能量</li><li>银钥能量达到 <strong>1000 点</strong> 时可发动钥令</li><li>钥令在战前装备，代表守密人的力量</li><li>混沌界域可加速银钥能量积累</li></ul><h2 id="卡牌类型" tabindex="-1">卡牌类型 <a class="header-anchor" href="#卡牌类型" aria-label="Permalink to &quot;卡牌类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><span class="card-type-badge card-command">指令卡</span></td><td>每位唤醒体 4 张，消耗算力使用</td></tr><tr><td><span class="card-type-badge card-spirit">灵魂觉醒卡</span></td><td>每位唤醒体 1 张，强力觉醒技能</td></tr><tr><td><span class="card-type-badge card-madness">狂气爆发</span></td><td>狂气满 100 触发，不消耗算力</td></tr></tbody></table><h2 id="队伍编成" tabindex="-1">队伍编成 <a class="header-anchor" href="#队伍编成" aria-label="Permalink to &quot;队伍编成&quot;">​</a></h2><ul><li>最多 <strong>4 名唤醒体</strong> 组成队伍</li><li>可装备一个钥令</li><li>建议阵容考虑界域协同</li></ul><h2 id="战斗技巧" tabindex="-1">战斗技巧 <a class="header-anchor" href="#战斗技巧" aria-label="Permalink to &quot;战斗技巧&quot;">​</a></h2><ol><li><strong>算力管理</strong> - 不要每回合都用光算力，留些余量应对突发</li><li><strong>狂气时机</strong> - 在关键时刻触发狂气爆发，最大化收益</li><li><strong>界域联动</strong> - 利用同界域卡牌的协同效果</li><li><strong>银钥规划</strong> - 针对不同敌人选择合适的钥令</li><li><strong>手牌管理</strong> - 注意手牌上限，合理使用或丢弃卡牌</li></ol>',18)])])}const g=a(l,[["render",o]]);export{m as __pageData,g as default};
